"""
Problem 1:
#
# SYNTAX:
# Syntax describes the Python building blocks used in this code —
# the keywords, operators, and structures that make it work.
#
def add_number(a, b):  # defines a function with parameters a, b
    return a + b  # return sends the result back to the caller
#
# Operators: +
# Built-in functions: sum()
#
# EVALUATION ORDER:
# Evaluation Order traces how Python reads and evaluates expressions.
# Inner expressions are evaluated first, then the outer ones.
#
print(add_number(5, 5))  # add_number() runs first, then print() outputs the result
print(add_num(5, 5))  # add_num() runs first, then print() outputs the result
add_number(a, b)  # arguments evaluated first, then function body runs
print(add_number(20, 30))  # add_number() runs first, then print() outputs the result
a + b  # a → then b → then +
#
# EXECUTION ORDER:
# Execution Order shows the sequence Python follows when running
# the code. 'def' and 'class' blocks are just stored, not run yet.
#
def add_number(a, b):  # stored in memory, not executed yet
print(add_number(...))  # add_number() runs with a=5, b=5
#   → import operator
#   → return operator.add(a, b)
def add_num(a, b):  # stored in memory, not executed yet
print(add_num(...))  # add_num() runs with a=5, b=5
#   → result = a + b
#   → return result
def add_number(a, b):  # stored in memory, not executed yet
def add_number(a, b):  # stored in memory, not executed yet
a = ...  # assigns a value to the variable
b = ...  # assigns a value to the variable
result = ...  # assigns a value to the variable
print(result)
print(add_number(...))  # add_number() runs with a=20, b=30
#   → import operator
#   → return operator.add(a, b)
#
# EXECUTION FLOW:
# Execution Flow tracks where Python jumps during runtime — which
# blocks are skipped and which actually run.
#
# def blocks are skipped at runtime — add_num, add_number are stored in memory
#
# Execution starts at the top-level code (outside def/class):
#   → print(add_number(...))  # add_number() runs first → value goes to print()
#   → print(add_num(...))  # add_num() runs first → value goes to print()
#   → a = ...  # stored in memory
#   → b = ...  # stored in memory
#   → result = ...  # stored in memory
#   → print(result)
#   → print(add_number(...))  # add_number() runs first → value goes to print()

"""

