#
def sort_list_descending(lst):  # defines a function with parameters lst
    def sort():
        sorted_list = []
        while lst:
            maximum = lst[0]
            for item in lst:
                if item > maximum:
                    maximum = item
            sorted_list.append(maximum)
            lst.remove(maximum)
        return sorted_list
